import { Alchemy, Network } from 'alchemy-sdk';
import { useEffect, useState } from 'react';
import "./blockStyles.css";

// Refer to the README doc for more information about using API
// keys in client-side code. You should never do this in production
// level code.
const settings = {
  apiKey: process.env.REACT_APP_ALCHEMY_API_KEY,
  network: Network.ETH_MAINNET,
};


// In this week's lessons we used ethers.js. Here we are using the
// Alchemy SDK is an umbrella library with several different packages.
//
// You can read more about the packages here:
//   https://docs.alchemy.com/reference/alchemy-sdk-api-surface-overview#api-surface
const alchemy = new Alchemy(settings);

export default function BlockExplorerPage() {
  const [blockNumber, setBlockNumber] = useState();
  const [block, setBlock] = useState(null);
  const [loading, setLoading] = useState(true);

  // NFT state
  const [nftContract, setNftContract] = useState("");
  const [tokenId, setTokenId] = useState("");
  const [nftData, setNftData] = useState(null);
  const [floorPrice, setFloorPrice] = useState(null);

  // Pending tx state
  const [pendingTxHash, setPendingTxHash] = useState("");
  const [txStatus, setTxStatus] = useState(null);

  // Asset transfers
  const [address, setAddress] = useState("");
  const [transfers, setTransfers] = useState([]);

  useEffect(() => {
    async function loadBlock() {
      setLoading(true);
      const number = await alchemy.core.getBlockNumber();
      setBlockNumber(number);
      const blockInfo = await alchemy.core.getBlockWithTransactions(number);
      setBlock(blockInfo);
      setLoading(false);
    }
    loadBlock();
  }, []);

  // Obtener metadata NFT
  const fetchNFT = async () => {
    try {
      const data = await alchemy.nft.getNftMetadata(nftContract, tokenId);
      setNftData(data);
      const floor = await alchemy.nft.getFloorPrice(nftContract);
      setFloorPrice(floor.openSea?.floorPrice || floor.looksRare?.floorPrice || "N/A");
    } catch (err) {
      console.error(err);
    }
  };

  // Ver si transacción pendiente se minó
  const checkTx = async () => {
    try {
      const receipt = await alchemy.core.getTransactionReceipt(pendingTxHash);
      if (!receipt) setTxStatus("Pending...");
      else setTxStatus(receipt.status === 1 ? "Success" : "Failed");
    } catch (err) {
      console.error(err);
    }
  };

  // Obtener transferencias de dirección
  const getTransfers = async () => {
    try {
      const txs = await alchemy.core.getAssetTransfers({
        fromBlock: "0x0",
        toBlock: "latest",
        toAddress: address,
        category: ["erc20", "erc721", "erc1155"]
      });
      setTransfers(txs.transfers);
    } catch (err) {
      console.error(err);
    }
  };

  if (loading) return <p className="loading">Loading block data...</p>;

  return (
    <div className="etherscan-container">
      <h1 className="etherscan-title">Block #{blockNumber}</h1>

      {/* Block summary */}
      <div className="block-card">
        <h2>Block Summary</h2>
        <div className="card-content">
          <div className="card-item"><strong>Block Number:</strong> {block.number}</div>
          <div className="card-item"><strong>Timestamp:</strong> {new Date(block.timestamp * 1000).toLocaleString()}</div>
          <div className="card-item"><strong>Miner:</strong> <span className="mono">{block.miner}</span></div>
          <div className="card-item"><strong>Hash:</strong> <span className="mono">{block.hash}</span></div>
          <div className="card-item"><strong>Transactions:</strong> {block.transactions.length}</div>
        </div>
      </div>

      {/* Transactions */}
      <div className="block-card">
        <h2>Transactions</h2>
        <div className="card-content">
          {block.transactions.slice(0, 10).map(tx => (
            <div key={tx.hash} className="tx-card">
              <div><strong>Hash:</strong> <span className="mono hash">{tx.hash}</span></div>
              <div><strong>From:</strong> <span className="mono">{tx.from}</span></div>
              <div><strong>To:</strong> <span className="mono">{tx.to || "Contract creation"}</span></div>
              <div><strong>Value:</strong> {(Number(tx.value)/1e18).toFixed(4)} ETH</div>
              <div>
                <button className="button-copy" onClick={() => navigator.clipboard.writeText(tx.hash)}>Copy Hash</button>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* NFT metadata */}
      <div className="block-card">
        <h2>NFT Info</h2>
        <div className="card-content">
          <input placeholder="Contract Address" value={nftContract} onChange={e=>setNftContract(e.target.value)} />
          <input placeholder="Token ID" value={tokenId} onChange={e=>setTokenId(e.target.value)} />
          <button className="button-copy" onClick={fetchNFT}>Fetch NFT</button>

          {nftData && (
            <div className="card-item">
              <div><strong>Name:</strong> {nftData.title}</div>
              <div><strong>Description:</strong> {nftData.description}</div>
              <div><strong>Floor Price:</strong> {floorPrice} ETH</div>
              {nftData.media[0]?.gateway && <img src={nftData.media[0].gateway} alt="NFT" style={{maxWidth:"150px"}} />}
            </div>
          )}
        </div>
      </div>

      {/* Pending transaction */}
      <div className="block-card">
        <h2>Pending Transaction Status</h2>
        <input placeholder="Transaction Hash" value={pendingTxHash} onChange={e=>setPendingTxHash(e.target.value)} />
        <button className="button-copy" onClick={checkTx}>Check Status</button>
        {txStatus && <p>Status: {txStatus}</p>}
      </div>

      {/* Address transfers */}
      <div className="block-card">
        <h2>Transfers Received by Address</h2>
        <input placeholder="Address" value={address} onChange={e=>setAddress(e.target.value)} />
        <button className="button-copy" onClick={getTransfers}>Get Transfers</button>

        {transfers.length > 0 && (
          <div className="card-content">
            {transfers.slice(0,10).map(tx => (
              <div key={tx.hash} className="tx-card">
                <div><strong>Hash:</strong> <span className="mono hash">{tx.hash}</span></div>
                <div><strong>From:</strong> <span className="mono">{tx.from}</span></div>
                <div><strong>To:</strong> <span className="mono">{tx.to}</span></div>
                <div><strong>Token:</strong> {tx.asset || "ETH"}</div>
              </div>
            ))}
          </div>
        )}
      </div>

    </div>
  );
}
